var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"시공간 수정의 후유증은 꽤나 다양해, 친구.","JPN":"時空間修正の後遺症は、かなり様々だ。","ENG":"Side effects of spacetime recalibration are quite diverse, my friend.","TWN":"修正時空會引起多種後遺症，朋友。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"특히나 자네처럼 많이 겪은 경우에는...... 무슨 일이 일어날지 장담할 수 없어.","JPN":"特に君のように、色んなことがあった場合……何が起きるかわからない。","ENG":"And for someone who has done it multiple times like yourself, there's no telling what might happen.","TWN":"特別是像你這種經歷了很多次的情況……我無法保證會發生什麼。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 자네의 길잡이로서, 이것 하나는 얘기해 줄 수 있겠군.","JPN":"だが、君のガイドとして、これだけは言える。","ENG":"But as your guide, I can tell you this.","TWN":"但作為你的領路人，我可以告訴你一點。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"꿈에서 다른 사람과 눈을 마주치게 되더라도 너무 놀라진 마. 그건 실제가 아니고, 그들의 추억을 잠시 관측하는 것 뿐이니까.","JPN":"夢の中で他の人と目が合っても、あまり驚くな。それは現実ではなく、彼らの思い出を少し観察するにすぎない。","ENG":"Don't be too surprised if you get to make eye contact with someone else. It's not real. You're observing their memories for a short period of time.","TWN":"在夢裡，即使與他人對上視線也不要太驚訝。因為那並不是現實，你只是在暫時觀看他們的回憶而已。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 사람들의 행복했던 시절을 함께 돌아보는 것도...... 자네가 앞으로 걸을 길에 작은 위안 정도는 되겠지.","JPN":"だが、誰かの幸せだった時期を一緒に振り返るのも……これから君が歩むべき道の、小さな癒しにはなるだろう。","ENG":"But looking back at people's memories of their happy past could provide some comfort for your mind while walking the path you're on.","TWN":"不過，與他人一同觀看幸福的回憶……或許能在你前行的道路上，成為小小的慰藉。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"이거하고...... 이걸, 다음과 같은 배율로 섞어주면......","JPN":"これと……これを、次の比率で混ぜると……","ENG":"And if I mix this and this at a certain ratio...","TWN":"這個……還有這個，把它們以相同的比例混在一起……"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"......튼튼해지는 약~ 완성! 헤헤.","JPN":"……元気になる薬～完成！　ヘヘ。","ENG":"There! An anti-fatigue potion! Heh heh.","TWN":"……變強壯的藥～完成！嘿嘿。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"으윽, 맛없어.","JPN":"うぅっ、不味い。","ENG":"Ew, it tastes awful.","TWN":"呃，一點也不好喝。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"그렇다면...... 배합식을 조금 바꿔볼까?","JPN":"じゃあ今度は……配合式を変えてみようかな？","ENG":"Then... What if I change the formula just a little bit?","TWN":"這樣說來……要不要改變一下組合公式？"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"체리, 체리...... 포도, 포도......","JPN":"チェリー、チェリー……ブドウ、ブドウ……","ENG":"Cherry, cherry... Grapes, grapes...","TWN":"櫻桃，櫻桃……葡萄，葡萄……"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"여기에 라임을 한 스푼 첨가해주면......!","JPN":"ここにライムを大さじ一杯加えたら……！","ENG":"And a spoonful of lime...","TWN":"再加入一勺酸橙汁……!"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"맛 좋은 주스 완성!","JPN":"おいしいジュースの完成！","ENG":"There! Refreshing juice!","TWN":"美味的果汁就做好啦！"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"음~ 새콤달콤해~","JPN":"う～ん、甘酸っぱ～い。","ENG":"*Gulp, gulp* Mmm, nice and refreshing!","TWN":"嗯～酸酸甜甜的～"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"......아차!","JPN":"……しまった！","ENG":"Uh-oh.","TWN":"……哎呀！"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"이러면 그냥 주스가 됐을 뿐이잖아!","JPN":"これだと、ただのジュースと同じじゃない！","ENG":"What am I doing? This is just a cup of juice, not a potion!","TWN":"這樣不就只是果汁了嘛！"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"으음...... 그렇지만 튼튼해지는 약은 메롱하게 되는 맛이라 먹기 싫은데.","JPN":"うーん……でも元気になる薬は苦すぎて飲みたくないんだよね。","ENG":"Hngh... But the anti-fatigue potion tastes just too horrible.","TWN":"嗯……但是變強壯的藥又太難喝了，不想喝。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JANE_MASON_NULL_CHILD","text":{"KOREA":"저기요! 정장 어른 씨!","JPN":"すみません！　スーツのおじさん！","ENG":"Excuse me! You there in a suit!","TWN":"您好！這位穿西裝的大人！"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_CHILD","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};